CREATE TABLE IF NOT EXISTS governance_policies(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,code text NOT NULL,title text NOT NULL,category text NOT NULL,owner text NOT NULL,status text NOT NULL DEFAULT 'draft',current_version_id uuid,published_at timestamptz,expires_at timestamptz,review_at timestamptz,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,code));
CREATE TABLE IF NOT EXISTS governance_policy_versions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,policy_id uuid NOT NULL,version text NOT NULL,content text NOT NULL,summary text NOT NULL DEFAULT '',status text NOT NULL DEFAULT 'draft',created_by text NOT NULL DEFAULT '',submitted_at timestamptz,approver text NOT NULL DEFAULT '',approval_comments text NOT NULL DEFAULT '',approved_at timestamptz,published_at timestamptz,supersedes_version_id uuid,metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(policy_id,version));
CREATE TABLE IF NOT EXISTS governance_policy_acknowledgements(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,policy_id uuid NOT NULL,version_id uuid NOT NULL,subject_id text NOT NULL,status text NOT NULL DEFAULT 'pending',due_at timestamptz NOT NULL,acknowledged_at timestamptz,attestation text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(version_id,subject_id));
CREATE TABLE IF NOT EXISTS governance_policy_exceptions(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,policy_id uuid NOT NULL,requestor text NOT NULL,reason text NOT NULL,status text NOT NULL DEFAULT 'pending',expires_at timestamptz NOT NULL,decided_by text NOT NULL DEFAULT '',decided_at timestamptz,comments text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}'::jsonb,created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS idx_governance_policies_review ON governance_policies(tenant_id,status,review_at);CREATE INDEX IF NOT EXISTS idx_policy_ack_due ON governance_policy_acknowledgements(tenant_id,status,due_at);CREATE INDEX IF NOT EXISTS idx_policy_exception_expiry ON governance_policy_exceptions(tenant_id,status,expires_at);
ALTER TABLE governance_policies ADD CONSTRAINT uq_governance_policies_tenant_id UNIQUE(tenant_id,id);
ALTER TABLE governance_policy_versions ADD CONSTRAINT uq_governance_policy_versions_tenant_id UNIQUE(tenant_id,id), ADD CONSTRAINT fk_policy_versions_policy_tenant FOREIGN KEY(tenant_id,policy_id) REFERENCES governance_policies(tenant_id,id) ON DELETE CASCADE;
ALTER TABLE governance_policy_acknowledgements ADD CONSTRAINT fk_policy_ack_policy_tenant FOREIGN KEY(tenant_id,policy_id) REFERENCES governance_policies(tenant_id,id) ON DELETE CASCADE, ADD CONSTRAINT fk_policy_ack_version_tenant FOREIGN KEY(tenant_id,version_id) REFERENCES governance_policy_versions(tenant_id,id) ON DELETE CASCADE;
ALTER TABLE governance_policy_exceptions ADD CONSTRAINT fk_policy_exceptions_policy_tenant FOREIGN KEY(tenant_id,policy_id) REFERENCES governance_policies(tenant_id,id) ON DELETE CASCADE;
ALTER TABLE governance_policies ADD CONSTRAINT fk_governance_current_version_tenant FOREIGN KEY(tenant_id,current_version_id) REFERENCES governance_policy_versions(tenant_id,id) DEFERRABLE INITIALLY DEFERRED;
